<script setup lang="ts">
import { computed, ref } from 'vue';
import { useRouter, useRoute } from 'vue-router';
import { ArrowLeft, Download } from 'lucide-vue-next';
import { useRollCallStore } from '@/store/useRollCallStore';
import { useAdminStore } from '@/store/useAdminStore';
import { exportCsv } from '@/utils/exportCsv';
import dayjs from 'dayjs';

interface DayAtt {
  date: string;
  weekday: string;
  status: 'signedIn' | 'absent';
  time?: string;
}

const STATUS_STYLE = {
  signedIn: { bg: '#F0FDF4', text: '#22C55E', label: '已到岗' },
  absent: { bg: '#FEF2F2', text: '#EF4444', label: '缺勤' },
} as const;

const AVATAR_COLOR = '#E53E3E';
const avatarText = (name: string) => name.slice(0, 2);

type Period = 'today' | 'week' | 'month';

const PERIOD_TABS: { key: Period; label: string }[] = [
  { key: 'today', label: '今日' },
  { key: 'week', label: '本周' },
  { key: 'month', label: '本月' },
];

const WEEKDAY_MAP = ['星期日', '星期一', '星期二', '星期三', '星期四', '星期五', '星期六'];

const PERIOD_LABEL: Record<Period, string> = {
  today: '今日',
  week: '本周',
  month: '本月',
};

function formatDateCN(dateStr: string): string {
  const d = new Date(dateStr + 'T00:00:00');
  return `${d.getMonth() + 1}月${d.getDate()}日`;
}

function getWeekdayCN(dateStr: string): string {
  const d = new Date(dateStr + 'T00:00:00');
  return WEEKDAY_MAP[d.getDay()];
}

const router = useRouter();
const route = useRoute();
const id = computed(() => route.params.id as string);

const store = useRollCallStore();
const adminStore = useAdminStore();

const toast = ref(false);
const toastMsg = ref('');
const period = ref<Period>('week');
const exporting = ref(false);
let toastTimer: ReturnType<typeof setTimeout> | null = null;

const merchant = computed(() => store.merchants.find((m) => m.id === id.value));

const merchantRecords = computed(() => adminStore.records.filter((r) => r.merchantId === id.value));

const BASE_DATE = dayjs().format('YYYY-MM-DD');

const periodData = computed(() => {
  const base = new Date(BASE_DATE + 'T00:00:00');

  const filterByPeriod = (p: Period) => {
    if (p === 'today') {
      return merchantRecords.value.filter((r) => r.date === BASE_DATE);
    }
    const days = p === 'week' ? 7 : 30;
    const start = new Date(base);
    start.setDate(start.getDate() - (days - 1));
    const startStr = start.toISOString().slice(0, 10);
    return merchantRecords.value.filter((r) => r.date >= startStr && r.date <= BASE_DATE);
  };

  const calcStats = (filtered: typeof merchantRecords.value) => {
    const active = filtered.filter((r) => r.status === 'signedIn' || r.status === 'absent');
    const total = active.length;
    const present = active.filter((r) => r.status === 'signedIn').length;
    const absent = active.filter((r) => r.status === 'absent').length;
    const rate = total > 0 ? Math.round((present / total) * 100) : 0;
    const days: DayAtt[] = active
      .slice()
      .sort((a, b) => b.date.localeCompare(a.date))
      .map((r) => ({
        date: formatDateCN(r.date),
        weekday: getWeekdayCN(r.date),
        status: r.status === 'signedIn' ? 'signedIn' : 'absent',
        time: r.signedAt,
      }));
    return { total, present, absent, rate, days };
  };

  return {
    today: calcStats(filterByPeriod('today')),
    week: calcStats(filterByPeriod('week')),
    month: calcStats(filterByPeriod('month')),
  };
});

const absentDates = computed(() =>
  periodData.value.month.days.filter((d) => d.status === 'absent').map((d) => d.date)
);

const status = computed(() => {
  const m = merchant.value;
  if (!m) return 'unsigned';
  if (m.signedIn) return 'signedIn';
  if (m.absent) return 'absent';
  return 'unsigned';
});

const statusLabel = computed(() => {
  if (status.value === 'signedIn') return '已到岗';
  if (status.value === 'absent') return '缺勤';
  return '未签到';
});

const data = computed(() => periodData.value[period.value]);

function showToast(msg: string) {
  toastMsg.value = msg;
  toast.value = true;
  if (toastTimer) clearTimeout(toastTimer);
  toastTimer = setTimeout(() => (toast.value = false), 2000);
}

function handleExport() {
  const m = merchant.value;
  if (!m) return;
  exporting.value = true;
  try {
    const rows = data.value.days.map((d) => ({
      商户名称: m.name,
      日期: d.date,
      星期: d.weekday,
      状态: d.status === 'signedIn' ? '已到岗' : '缺勤',
      签到时间: d.time || '-',
    }));
    exportCsv(rows, `${m.name}_${PERIOD_LABEL[period.value]}考勤`);
    showToast(`已导出 ${m.name} ${PERIOD_LABEL[period.value]}考勤`);
  } finally {
    exporting.value = false;
  }
}
</script>

<template>
  <div v-if="!merchant" class="flex h-full items-center justify-center text-sm text-muted">
    商户不存在
  </div>
  <div v-else class="relative pb-8 bg-base">
    <!-- 主题色头部渐变 + 居中大圆头像 -->
    <div class="merchant-header-gradient px-4 pb-12 pt-4">
      <div class="flex items-center justify-between">
        <button
          type="button"
          class="flex h-8 w-8 items-center justify-center rounded-full bg-white/20 text-white active:scale-95"
          @click="router.push('/merchants')"
        >
          <ArrowLeft :size="16" :stroke-width="2.5" />
        </button>
        <h1 class="text-base font-bold text-white">商户详情</h1>
        <div class="w-8" />
      </div>

      <div class="mt-5 flex flex-col items-center">
        <div class="relative">
          <img
            v-if="merchant.avatar"
            :src="merchant.avatar"
            :alt="merchant.name"
            class="h-20 w-20 rounded-full object-cover shadow-lg ring-4 ring-white/30"
          />
          <div
            v-else
            class="flex h-20 w-20 items-center justify-center rounded-full text-2xl font-bold text-white shadow-lg ring-4 ring-white/30"
            :style="{ backgroundColor: AVATAR_COLOR }"
          >
            {{ avatarText(merchant.name) }}
          </div>
        </div>
        <h2 class="mt-3 text-xl font-bold text-white">{{ merchant.name }}</h2>
        <p class="mt-1 text-sm text-white/80">
          {{ merchant.floor }} · {{ merchant.location }}
        </p>
        <span class="mt-2.5 rounded-full bg-white/25 px-3 py-0.5 text-xs font-medium text-white">
          {{ statusLabel }}
        </span>
      </div>
    </div>

    <!-- 下方卡片区域 -->
    <div class="flex flex-col gap-2 px-4">
      <!-- 模块1：每日考勤卡 -->
      <div class="-mt-6 rounded-2xl bg-card p-4 shadow-sm">
        <div class="flex items-center justify-between">
          <h2 class="text-sm font-semibold text-ink">考勤明细</h2>
          <button
            type="button"
            class="flex items-center gap-1.5 rounded-lg bg-primary px-3 py-1.5 text-xs font-medium text-white transition-colors hover:bg-primary-dark active:scale-95"
            :disabled="exporting"
            @click="handleExport"
          >
            <Download :size="12" />
            导出{{ PERIOD_LABEL[period] }}考勤
          </button>
        </div>

        <!-- 周期切换 Tab -->
        <div class="mt-3 flex rounded-lg bg-base p-1">
          <button
            v-for="t in PERIOD_TABS"
            :key="t.key"
            type="button"
            class="flex-1 rounded-md py-1.5 text-xs font-medium transition-all"
            :class="period === t.key ? 'bg-card text-primary shadow-sm' : 'text-muted'"
            @click="period = t.key"
          >
            {{ t.label }}
          </button>
        </div>

        <!-- 每日列表 -->
        <div class="mt-3 space-y-2">
          <div
            v-for="d in data.days"
            :key="d.date"
            class="flex items-center justify-between rounded-xl bg-base px-3.5 py-3"
          >
            <div class="flex items-center gap-2">
              <span class="text-sm font-medium text-ink">{{ d.date }}</span>
              <span class="text-xs text-muted">{{ d.weekday }}</span>
              <span v-if="d.time" class="text-xs text-muted">{{ d.time }}</span>
            </div>
            <span
              class="inline-flex items-center gap-1 rounded-full px-2.5 py-0.5 text-xs font-medium"
              :style="{ backgroundColor: STATUS_STYLE[d.status].bg, color: STATUS_STYLE[d.status].text }"
            >
              <span
                class="inline-block h-1.5 w-1.5 rounded-full"
                :style="{ backgroundColor: STATUS_STYLE[d.status].text }"
              />
              {{ STATUS_STYLE[d.status].label }}
            </span>
          </div>
        </div>
      </div>

      <!-- 模块2：考勤统计 4 宫格卡 -->
      <div class="rounded-2xl bg-card p-4 shadow-sm">
        <div class="mb-3 flex items-center justify-between">
          <h2 class="text-sm font-semibold text-ink">考勤统计</h2>
          <span class="text-xs text-muted">{{ PERIOD_LABEL[period] }}</span>
        </div>
        <div class="grid grid-cols-4 gap-2 rounded-xl bg-base p-3">
          <div class="text-center">
            <p class="text-xs text-muted">应签到</p>
            <p class="mt-1 text-lg font-bold text-ink">
              {{ data.total }}<span class="text-xs font-normal text-muted">天</span>
            </p>
          </div>
          <div class="text-center">
            <p class="text-xs text-muted">实际到岗</p>
            <p class="mt-1 text-lg font-bold text-primary">
              {{ data.present }}<span class="text-xs font-normal text-muted">天</span>
            </p>
          </div>
          <div class="text-center">
            <p class="text-xs text-muted">缺勤</p>
            <p class="mt-1 text-lg font-bold text-[#EF4444]">
              {{ data.absent }}<span class="text-xs font-normal text-muted">天</span>
            </p>
          </div>
          <div class="text-center">
            <p class="text-xs text-muted">考勤率</p>
            <p class="mt-1 text-lg font-bold text-[#3B82F6]">
              {{ data.rate }}<span class="text-xs font-normal text-muted">%</span>
            </p>
          </div>
        </div>
      </div>

      <!-- 模块3：缺勤记录汇总卡 -->
      <div class="rounded-2xl bg-card p-4 shadow-sm">
        <h2 class="mb-2 text-sm font-semibold text-ink">缺勤记录汇总</h2>
        <div class="flex flex-wrap gap-2">
          <span
            v-for="d in absentDates"
            :key="d"
            class="rounded-full bg-red-50 px-2.5 py-1 text-xs font-medium text-[#EF4444] dark:bg-red-500/15"
          >
            {{ d }}
          </span>
          <span v-if="absentDates.length === 0" class="text-xs text-muted">暂无缺勤记录</span>
        </div>
      </div>
    </div>

    <!-- toast -->
    <div
      v-if="toast"
      class="fixed inset-x-0 top-1/2 z-[60] flex -translate-y-1/2 justify-center px-4"
    >
      <div class="rounded-xl bg-black/85 px-4 py-3 text-center text-[12px] text-white shadow-lg">
        {{ toastMsg }}
      </div>
    </div>
  </div>
</template>
